import{_ as e,a as n,b as r,c as i}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as l,o as t,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Other/magnet-transfer.md","filePath":"tr-TR/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"tr-TR/Other/magnet-transfer.md"};function m(k,a,y,u,p,b){return t(),d("div",null,[...a[0]||(a[0]=[o('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer, magnet link üzerinden dosyaları indirir ve seçtiğiniz bulut depolama kanalına otomatik olarak yükler.</p><p>Anime bölümleri, videolar, arşivler ve benzeri dosyaları taşımak için kullanışlıdır. Magnet link yapıştırdığınızda ImgBed arka planda bir indirme görevi oluşturur. İndirme tamamlandıktan sonra dosya ImgBed&#39;e yüklenir ve son bağlantı yükleme listesinde görünür.</p><p><img src="'+e+'" alt="Magnet transfer" loading="lazy"></p><h2 id="nerede-kullanılır" tabindex="-1">Nerede Kullanılır? <a class="header-anchor" href="#nerede-kullanılır" aria-label="Permalink to &quot;Nerede Kullanılır?&quot;">​</a></h2><p>Magnet transfer girişi ana sayfadaki yükleme alanındadır.</p><p>Magnet link&#39;i giriş kutusuna yapıştırın, <code>Transfer</code> seçin, ardından yükleyin.</p><p><img src="'+n+'" alt="Anime yükleme" loading="lazy"></p><h2 id="ilk-kullanımdan-once" tabindex="-1">İlk Kullanımdan Önce <a class="header-anchor" href="#ilk-kullanımdan-once" aria-label="Permalink to &quot;İlk Kullanımdan Önce&quot;">​</a></h2><p>Önce yönetim panelinde magnet transfer yapılandırın.</p><p>Genellikle şunlar gerekir:</p><ol><li>İndirme görevini çalıştırmak için GitHub hesabı.</li><li>Google Drive veya OneDrive gibi bir cloud upload channel.</li><li>Hedef yükleme dizini.</li><li>Görev zaman aşımı.</li></ol><p>Ayarlar hazır olduğunda ana sayfaya dönün ve transfer başlatmak için magnet link yapıştırın.</p><h2 id="magnet-link-yukleme" tabindex="-1">Magnet Link Yükleme <a class="header-anchor" href="#magnet-link-yukleme" aria-label="Permalink to &quot;Magnet Link Yükleme&quot;">​</a></h2><ol><li>Magnet link&#39;i ana sayfadaki yükleme kutusuna yapıştırın.</li><li>Modun <code>Transfer</code> olduğundan emin olun.</li><li>Upload düğmesine tıklayın.</li><li>ImgBed&#39;in magnet task oluşturmasını bekleyin.</li><li>Görev başladıktan sonra ilerlemeyi kontrol etmek için sağ alt köşedeki <code>Magnet Tasks</code> yüzen panelini kullanın.</li></ol><p>Download ve upload zaman alabilir. Hız magnet kaynağına, GitHub runtime ortamına ve seçili cloud storage channel&#39;a bağlıdır.</p><p><img src="'+r+'" alt="Magnet indiriliyor" loading="lazy"></p><h2 id="tamamlandıktan-sonra" tabindex="-1">Tamamlandıktan Sonra <a class="header-anchor" href="#tamamlandıktan-sonra" aria-label="Permalink to &quot;Tamamlandıktan Sonra&quot;">​</a></h2><p>Görev tamamlandığında yükleme listesinde dosya adı ve bağlantı görünür.</p><p>Videolarda video preview, görsellerde image preview, diğer dosyalarda normal dosya simgesi gösterilir.</p><p><img src="'+i+'" alt="İndirilen video" loading="lazy"></p><p>Şunları kopyalayabilirsiniz:</p><table tabindex="0"><thead><tr><th>Bağlantı Türü</th><th>Kullanım</th></tr></thead><tbody><tr><td>Original link</td><td>Doğrudan dosya erişimi</td></tr><tr><td>Markdown</td><td>Markdown yazıları veya notlar</td></tr><tr><td>HTML</td><td>Web sayfası kodu</td></tr><tr><td>BBCode</td><td>BBCode destekleyen forumlar</td></tr></tbody></table><h2 id="magnet-task-paneli" tabindex="-1">Magnet Task Paneli <a class="header-anchor" href="#magnet-task-paneli" aria-label="Permalink to &quot;Magnet Task Paneli&quot;">​</a></h2><p>Sağ alttaki magnet task paneli görev sayısını, görev adını, ilerlemeyi ve son durumu gösterir.</p><p>Yaygın durumlar:</p><table tabindex="0"><thead><tr><th>Durum</th><th>Anlamı</th></tr></thead><tbody><tr><td>Waiting</td><td>Görev oluşturuldu ve çalışmayı bekliyor.</td></tr><tr><td>Downloading</td><td>Magnet kaynağı indiriliyor.</td></tr><tr><td>Uploading</td><td>Dosya indirildi ve bulut depolamaya yükleniyor.</td></tr><tr><td>Completed</td><td>Upload başarılı, bağlantı kopyalanabilir.</td></tr><tr><td>Failed</td><td>Görev başarıyla tamamlanmadı. Mesajı kontrol edip yeniden deneyin.</td></tr></tbody></table><h2 id="ipucları" tabindex="-1">İpuçları <a class="header-anchor" href="#ipucları" aria-label="Permalink to &quot;İpuçları&quot;">​</a></h2><ul><li>Magnet link birden fazla dosya içeriyorsa ImgBed gösterim için ana tamamlanan dosyaya öncelik verir.</li><li>Büyük dosyalar daha uzun sürer. Sayfayı yenilemeden önce görevin bitmesini bekleyin.</li><li>Magnet kaynağında kullanılabilir peers yoksa indirme çok yavaş olabilir veya başarısız olabilir.</li><li>Bulut hesabında kota kalmadıysa, yetkilendirme süresi dolduysa veya yükleme dizini yanlışsa görev başarısız olabilir.</li><li>Video preview yükleme tamamlandıktan birkaç saniye sonra görünebilir.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="magnet-link-yapıstırdıktan-sonra-hicbir-sey-baslamıyor" tabindex="-1">Magnet Link Yapıştırdıktan Sonra Hiçbir Şey Başlamıyor <a class="header-anchor" href="#magnet-link-yapıstırdıktan-sonra-hicbir-sey-baslamıyor" aria-label="Permalink to &quot;Magnet Link Yapıştırdıktan Sonra Hiçbir Şey Başlamıyor&quot;">​</a></h3><p>Yönetim panelinde magnet transfer etkin olduğundan ve kullanılabilir bir GitHub hesabı ile bulut kanalının seçildiğinden emin olun.</p><h3 id="indirme-hep-yavas" tabindex="-1">İndirme Hep Yavaş <a class="header-anchor" href="#indirme-hep-yavas" aria-label="Permalink to &quot;İndirme Hep Yavaş&quot;">​</a></h3><p>Magnet hızı kaynağın kendisine bağlıdır. Kullanılabilir peers yoksa indirme çok yavaş veya imkansız olabilir.</p><h3 id="upload-sonrası-preview-gorunmuyor" tabindex="-1">Upload Sonrası Preview Görünmüyor <a class="header-anchor" href="#upload-sonrası-preview-gorunmuyor" aria-label="Permalink to &quot;Upload Sonrası Preview Görünmüyor&quot;">​</a></h3><p>Önce dosya bağlantısının açıldığını doğrulayın. Video dosyalarının tarayıcıda yüklenmesi kısa sürebilir veya bağlantıyı doğrudan açabilirsiniz.</p><h3 id="gorev-basarısız-olursa-neyi-kontrol-etmeliyim" tabindex="-1">Görev Başarısız Olursa Neyi Kontrol Etmeliyim? <a class="header-anchor" href="#gorev-basarısız-olursa-neyi-kontrol-etmeliyim" aria-label="Permalink to &quot;Görev Başarısız Olursa Neyi Kontrol Etmeliyim?&quot;">​</a></h3><p>Magnet link&#39;in geçerli olup olmadığını, bulut kanalının çalışıp çalışmadığını ve yükleme dizininin doğru olup olmadığını kontrol edin. Sonra görevi tekrar gönderin.</p>',38)])])}const v=l(s,[["render",m]]);export{c as __pageData,v as default};
